127	+async function _decryptV1Legacy(msg, parsed, envelope) {
128	+  // v1 envelopes can only exist inside the TTL window at deploy time. The
129	+  // server's key endpoint now returns the v2 devices shape (no public_key
130	+  // field), so this path must NEVER fetch -- it only ever uses a peer key
131	+  // cached by a pre-deploy tab that never reloaded. On any fresh page load
132	+  // this cache is empty and every v1 envelope renders the sentinel below.
133	+  const peerUserId = _getDmPeerUserId(msg.room_id);
134	+  const cachedPeerKey = peerUserId && E2EE._legacyPeerKeys[peerUserId];
135	+  if (!cachedPeerKey || !parsed || !parsed.ct) {
136	+    dbg('[E2EE] v1 envelope with no cached pre-deploy peer key, sentinel, msg=' + msg.id);
137	+    return _sentinel(msg);
138	+  }
139	+  try {
140	+    const key = await E2EE._deriveSharedKeyV1(cachedPeerKey, msg.room_id);
141	+    const body = _partsFromB64(parsed.ct);
142	+    const plainBuf = await crypto.subtle.decrypt({ name: 'AES-GCM', iv: body.iv }, key, body.data);
143	+    const plaintext = new TextDecoder().decode(plainBuf);
144	+    if (!(await _validateDecryptedMedia(msg, plaintext))) {
